// ============================================================
// app.js — Article System v2 (dengan LocalStorage + Fetch)
// ============================================================

// === 1. KONSTANTA ===
const STORAGE_KEY = 'niura_articles';

// === 2. DOM ELEMENTS ===
const articleForm  = document.getElementById('articleForm');
const inputTitle   = document.getElementById('inputTitle');
const inputContent = document.getElementById('inputContent');
const tableBody    = document.getElementById('tableBody');
const toastNotif   = document.getElementById('toastNotif');

// === 3. STATE ===
let articles = [];

// === 4. STORAGE HELPERS ===
function saveToStorage() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(articles));
}

// === 5. RENDER ===
function renderTable(data = articles) {
  tableBody.innerHTML = '';
  if (data.length === 0) {
    tableBody.innerHTML = '<tr><td colspan="5" class="empty-state">Belum ada artikel.</td></tr>';
    return;
  }
  data.forEach((a, i) => {
    const tr = document.createElement('tr');
    tr.innerHTML = `
      <td>${i + 1}</td>
      <td>${escapeHTML(a.title)}</td>
      <td>${escapeHTML(a.content).substring(0, 80)}...</td>
      <td>${a.createdAt || '-'}</td>
      <td class="actions">
        <button class="btn-primary" onclick="setupEdit(${a.id})">Edit</button>
        <button class="btn-danger"  onclick="deleteArticle(${a.id})">Hapus</button>
      </td>`;
    tableBody.appendChild(tr);
  });
}

// Escape HTML untuk mencegah XSS
function escapeHTML(str) {
  const div = document.createElement('div');
  div.textContent = str;
  return div.innerHTML;
}

// === 6. UTILITIES ===
function clearForm() { inputTitle.value = ''; inputContent.value = ''; inputTitle.focus(); }
function showToast(msg, type = 'success') {
  toastNotif.textContent = msg;
  toastNotif.className = `toast ${type} show`;
  setTimeout(() => toastNotif.classList.remove('show'), 2500);
}

// === 7. CREATE ===
articleForm.addEventListener('submit', e => {
  e.preventDefault();
  const title   = inputTitle.value.trim();
  const content = inputContent.value.trim();
  if (!title)   { showToast('Judul wajib diisi!', 'error'); return; }
  if (!content) { showToast('Konten wajib diisi!', 'error'); return; }

  articles.push({
    id: Date.now(), title, content,
    createdAt: new Date().toLocaleDateString('id-ID')
  });
  saveToStorage();
  renderTable();
  clearForm();
  showToast('Artikel berhasil disimpan!');
});

// === 8. INIT (Fetch + Hydration) ===
async function initApp() {
  const stored = localStorage.getItem(STORAGE_KEY);
  if (stored) {
    articles = JSON.parse(stored);
  } else {
    try {
      const res = await fetch('./data.json');
      articles  = await res.json();
      saveToStorage();
    } catch (e) {
      articles = [];
    }
  }
  renderTable();
}

initApp();
